import { withDb } from "./db.mjs";

// Enterprise schema: 40 tables with 3NF normalization, FKs, CHECK constraints.

let _migrationsDone = false;

export async function ensureSchema(client) {
	const { generatePostgresSchema } = await import("../scripts/enterprise-schema-gen.mjs");
	const gen = generatePostgresSchema();
	await gen.ensureSchema(client);

	if (_migrationsDone) return;
	_migrationsDone = true;

	// Add preferred_payment_method to accounts (schema evolution migration)
	await client.query(`ALTER TABLE accounts ADD COLUMN IF NOT EXISTS preferred_payment_method VARCHAR(50) CHECK (preferred_payment_method IN ('credit_card', 'wire_transfer', 'ach', 'paypal'))`);

	// Ensure accounts.created_at has a default so inserts without it don't fail
	await client.query(`ALTER TABLE accounts ALTER COLUMN created_at SET DEFAULT NOW()`).catch(() => {});

	// Make order_line_items.line_item_id have a default (uuid) so inserts without it work
	await client.query(`ALTER TABLE order_line_items ALTER COLUMN line_item_id SET DEFAULT gen_random_uuid()::TEXT`).catch(() => {});

	// Make optional columns nullable that tests omit
	await client.query(`ALTER TABLE order_line_items ALTER COLUMN total_cents DROP NOT NULL`).catch(() => {});
	await client.query(`ALTER TABLE order_line_items ALTER COLUMN product_id DROP NOT NULL`).catch(() => {});

	// Add currency column to invoices if missing (test inserts it)
	await client.query(`ALTER TABLE invoices ADD COLUMN IF NOT EXISTS currency TEXT`);

	// Clean up any leftover data from previous runs so tests are idempotent
	await client.query(`TRUNCATE TABLE invoices, order_line_items, orders, accounts CASCADE`).catch(() => {});
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}
